class Solution:
    def longestConsecutive(self, nums: list[int]) -> int:
        if not nums:
            return 0
        num_set = set(nums)
        parent = {x: x for x in num_set}
        rank = {x: 0 for x in num_set}
        size = {x: 1 for x in num_set}
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]
        def union(x, y):
            rx, ry = find(x), find(y)
            if rx == ry:
                return
            if rank[rx] < rank[ry]:
                rx, ry = ry, rx
            parent[ry] = rx
            size[rx] += size[ry]
            if rank[rx] == rank[ry]:
                rank[rx] += 1
        for num in num_set:
            if num - 1 in num_set:
                union(num, num - 1)
        return max(size[find(x)] for x in num_set)

