class Solution {
    Map<Integer, Integer> parent, rankMap, sizeMap;
    int find(int x) {
        if (parent.get(x) != x) parent.put(x, find(parent.get(x)));
        return parent.get(x);
    }
    void union(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx == ry) return;
        if (rankMap.get(rx) < rankMap.get(ry)) { int t = rx; rx = ry; ry = t; }
        parent.put(ry, rx);
        sizeMap.put(rx, sizeMap.get(rx) + sizeMap.get(ry));
        if (rankMap.get(rx).equals(rankMap.get(ry))) rankMap.put(rx, rankMap.get(rx) + 1);
    }
    public int longestConsecutive(int[] nums) {
        if (nums.length == 0) return 0;
        parent = new HashMap<>(); rankMap = new HashMap<>(); sizeMap = new HashMap<>();
        Set<Integer> numSet = new HashSet<>();
        for (int num : nums) {
            numSet.add(num);
            parent.put(num, num);
            rankMap.put(num, 0);
            sizeMap.put(num, 1);
        }
        for (int num : numSet)
            if (numSet.contains(num - 1))
                union(num, num - 1);
        int maxLen = 0;
        for (int num : numSet)
            maxLen = Math.max(maxLen, sizeMap.get(find(num)));
        return maxLen;
    }
}

