use std::collections::{HashMap, HashSet};
impl Solution {
    pub fn longest_consecutive(nums: Vec<i32>) -> i32 {
        if nums.is_empty() {
            return 0;
        }
        let num_set: HashSet<i32> = nums.iter().cloned().collect();
        let mut parent: HashMap<i32, i32> = HashMap::new();
        let mut rank_map: HashMap<i32, i32> = HashMap::new();
        let mut size_map: HashMap<i32, i32> = HashMap::new();
        for &num in &num_set {
            parent.insert(num, num);
            rank_map.insert(num, 0);
            size_map.insert(num, 1);
        }
        fn find(parent: &mut HashMap<i32, i32>, x: i32) -> i32 {
            if *parent.get(&x).unwrap() != x {
                let p = *parent.get(&x).unwrap();
                let root = find(parent, p);
                parent.insert(x, root);
            }
            *parent.get(&x).unwrap()
        }
        fn union(parent: &mut HashMap<i32, i32>, rank: &mut HashMap<i32, i32>, size: &mut HashMap<i32, i32>, x: i32, y: i32) {
            let rx = find(parent, x);
            let ry = find(parent, y);
            if rx == ry { return; }
            let rx_rank = *rank.get(&rx).unwrap();
            let ry_rank = *rank.get(&ry).unwrap();
            if rx_rank < ry_rank {
                parent.insert(rx, ry);
                let rx_size = *size.get(&rx).unwrap();
                let ry_size = *size.get(&ry).unwrap();
                size.insert(ry, ry_size + rx_size);
            } else if rx_rank > ry_rank {
                parent.insert(ry, rx);
                let rx_size = *size.get(&rx).unwrap();
                let ry_size = *size.get(&ry).unwrap();
                size.insert(rx, rx_size + ry_size);
            } else {
                parent.insert(ry, rx);
                let rx_size = *size.get(&rx).unwrap();
                let ry_size = *size.get(&ry).unwrap();
                size.insert(rx, rx_size + ry_size);
                rank.insert(rx, rx_rank + 1);
            }
        }
        for &num in &num_set {
            if num_set.contains(&(num - 1)) {
                union(&mut parent, &mut rank_map, &mut size_map, num, num - 1);
            }
        }
        let mut max_len = 0;
        for &num in &num_set {
            let root = find(&mut parent, num);
            let s = *size_map.get(&root).unwrap();
            if s > max_len { max_len = s; }
        }
        max_len
    }
}

