use std::collections::HashMap;
impl Solution {
    pub fn num_islands2(m: i32, n: i32, positions: Vec<Vec<i32>>) -> Vec<i32> {
        let m = m as usize;
        let n = n as usize;
        let mut parent: HashMap<usize, usize> = HashMap::new();
        let mut rank_map: HashMap<usize, i32> = HashMap::new();
        let mut count = 0i32;
        let mut result = Vec::new();
        let dirs = [(-1i32, 0i32), (1, 0), (0, -1), (0, 1)];
        for pos in &positions {
            let r = pos[0] as usize;
            let c = pos[1] as usize;
            let key = r * n + c;
            if parent.contains_key(&key) {
                result.push(count);
                continue;
            }
            parent.insert(key, key);
            rank_map.insert(key, 0);
            count += 1;
            for &(dr, dc) in &dirs {
                let nr = r as i32 + dr;
                let nc = c as i32 + dc;
                if nr >= 0 && nr < m as i32 && nc >= 0 && nc < n as i32 {
                    let nkey = nr as usize * n + nc as usize;
                    if parent.contains_key(&nkey) {
                        let mut parent_local = parent.clone();
                        let mut rank_local = rank_map.clone();
                        let rx = *parent_local.get(&key).unwrap();
                        let ry = *parent_local.get(&nkey).unwrap();
                        let rx_root = Self::find_local(&mut parent_local, rx);
                        let ry_root = Self::find_local(&mut parent_local, ry);
                        if rx_root != ry_root {
                            let rx_rank = *rank_local.get(&rx_root).unwrap();
                            let ry_rank = *rank_local.get(&ry_root).unwrap();
                            if rx_rank < ry_rank {
                                parent.insert(rx_root, ry_root);
                            } else if rx_rank > ry_rank {
                                parent.insert(ry_root, rx_root);
                            } else {
                                parent.insert(ry_root, rx_root);
                                rank_map.insert(rx_root, rx_rank + 1);
                            }
                            count -= 1;
                        }
                    }
                }
            }
            result.push(count);
        }
        result
    }
    fn find_local(parent: &mut HashMap<usize, usize>, x: usize) -> usize {
        if *parent.get(&x).unwrap() != x {
            let p = *parent.get(&x).unwrap();
            let root = Self::find_local(parent, p);
            parent.insert(x, root);
        }
        *parent.get(&x).unwrap()
    }
}

