class Solution:
    def findRedundantDirectedConnection(self, edges: list[list[int]]) -> list[int]:
        n = len(edges)
        indegree = [0] * (n + 1)
        for u, v in edges:
            indegree[v] += 1
        candidates = [i for i in range(len(edges)) if indegree[edges[i][1]] == 2]
        def find(parent, x):
            if parent[x] != x:
                parent[x] = find(parent, parent[x])
            return parent[x]
        def union(parent, rank, x, y):
            rx, ry = find(parent, x), find(parent, y)
            if rx == ry:
                return False
            if rank[rx] < rank[ry]:
                rx, ry = ry, rx
            parent[ry] = rx
            if rank[rx] == rank[ry]:
                rank[rx] += 1
            return True
        def buildUF():
            parent = list(range(n + 1))
            rank = [0] * (n + 1)
            return parent, rank
        if candidates:
            for i in range(len(edges) - 1, -1, -1):
                if i == candidates[0]:
                    continue
                parent, rank = buildUF()
                ok = True
                for j in range(len(edges)):
                    if j == i:
                        continue
                    eu, ev = edges[j]
                    if not union(parent, rank, eu, ev):
                        ok = False
                        break
                if ok:
                    return edges[i]
            return edges[candidates[0]]
        else:
            parent, rank = buildUF()
            for i in range(len(edges)):
                if not union(parent, rank, edges[i][0], edges[i][1]):
                    return edges[i]
            return []

