impl Solution {
    pub fn find_redundant_directed_connection(edges: Vec<Vec<i32>>) -> Vec<i32> {
        let n = edges.len();
        let mut indegree = vec![0i32; n + 1];
        for e in &edges {
            indegree[e[1] as usize] += 1;
        }
        let mut candidate = -1i32;
        for i in (0..n).rev() {
            if indegree[edges[i][1] as usize] == 2 {
                candidate = i as i32;
                break;
            }
        }
        let solve = |skip: i32| -> Option<Vec<i32>> {
            let mut parent: Vec<usize> = (0..=n).collect();
            let mut rank_arr = vec![0i32; n + 1];
            fn find(parent: &mut Vec<usize>, x: usize) -> usize {
                if parent[x] != x {
                    parent[x] = find(parent, parent[x]);
                }
                parent[x]
            }
            fn union(parent: &mut Vec<usize>, rank: &mut Vec<i32>, x: usize, y: usize) -> bool {
                let rx = find(parent, x);
                let ry = find(parent, y);
                if rx == ry {
                    return false;
                }
                if rank[rx] < rank[ry] {
                    parent[rx] = ry;
                } else if rank[rx] > rank[ry] {
                    parent[ry] = rx;
                } else {
                    parent[ry] = rx;
                    rank[rx] += 1;
                }
                true
            }
            for (i, e) in edges.iter().enumerate() {
                if i as i32 == skip {
                    continue;
                }
                if !union(&mut parent, &mut rank_arr, e[0] as usize, e[1] as usize) {
                    return Some(e.clone());
                }
            }
            None
        };
        if candidate >= 0 {
            for i in (0..n).rev() {
                if i as i32 == candidate {
                    continue;
                }
                if let Some(result) = solve(i as i32) {
                    return result;
                }
            }
            return edges[candidate as usize].clone();
        }
        if let Some(result) = solve(-1) {
            return result;
        }
        vec![]
    }
}
